fn test_be7824e25ceb92a99421dacd2a0fea761fc358afd47425ee8e005e7c() {
    #[allow(unused_mut)]
    let mut wm = WordMotion::new(
        Tokenizer::try_new(KeywordCutter::new([]), "@,48-57,_,192-255")
            .unwrap(),
    );
    let output = wm
        .xmap(
            &[
                std::str::from_utf8(&[][..]).unwrap(),
                std::str::from_utf8(&[32u8, 100u8][..]).unwrap(),
                std::str::from_utf8(&[][..]).unwrap(),
                std::str::from_utf8(&[97u8, 98u8, 99u8, 32u8, 32u8][..])
                    .unwrap(),
                std::str::from_utf8(&[101u8, 102u8, 32u8, 32u8][..]).unwrap(),
                std::str::from_utf8(&[][..]).unwrap(),
                std::str::from_utf8(&[][..]).unwrap(),
                std::str::from_utf8(&[32u8][..]).unwrap(),
                std::str::from_utf8(&[103u8, 104u8][..]).unwrap(),
            ][..],
            &[92u8, 117u8, 48u8, 48u8, 49u8, 54u8][..],
            &[119u8][..],
            [0usize, 9usize, 2usize, 0usize],
            [0usize, 9usize, 3usize, 0usize],
            1u64,
        )
        .unwrap();
    assert_eq!(output.langle, [0usize, 9usize, 2usize, 0usize]);
    assert_eq!(output.prevent_change, &[49u8,][..]);
    assert_eq!(output.rangle, [0usize, 9usize, 3usize, 0usize]);
    assert_eq!(
        output.visualmode,
        &[92u8, 92u8, 117u8, 48u8, 48u8, 49u8, 54u8,][..]
    );
}

